  <svg viewBox="0 0 700 220" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="26" fill="#fafafa" font-size="13" font-weight="700" font-family="sans-serif">現物ETFの年間手数料比較 — モルガン・スタンレー「市場最安」で参入</text>
    <g font-family="sans-serif" font-size="11">
      <text x="15" y="58" fill="#71717a" font-size="10" font-weight="700">イーサリアム</text>
      <rect x="120" y="46" width="280" height="20" rx="4" fill="#f7931a"/>
      <text x="128" y="61" fill="#111113" font-size="10" font-weight="700">MSSE (モルガン)</text>
      <text x="410" y="61" fill="#f7931a" font-size="11" font-weight="700">0.14%</text>
